const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;

const basePremiumFor = (item: Item): number =>
  item.type === "sword" ? SWORD_BASE_PREMIUM : 0;

export const quote = (input: QuoteInput): number => {
  const base = input.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  return base + PROCESSING_FEE;
